import{_ as a,o,c as e,a2 as r}from"./chunks/framework.B3lafln9.js";const p=JSON.parse('{"title":"VanBot / Van-keyword 词库","description":"","frontmatter":{},"headers":[],"relativePath":"vanbot/index.md","filePath":"vanbot/index.md"}'),n={name:"vanbot/index.md"};function i(l,t,s,d,h,c){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="vanbot-van-keyword-词库" tabindex="-1">VanBot / Van-keyword 词库 <a class="header-anchor" href="#vanbot-van-keyword-词库" aria-label="Permalink to &quot;VanBot / Van-keyword 词库&quot;">​</a></h1><p><em>适配 NoneBot 的 Python 词库</em></p><p>为 VanBot 量身打造，提供高效、可扩展的关键词支持，无缝集成对话交互、指令匹配等核心功能，助力 VanBot 快速实现智能回复。</p><p><a href="https://www.python.org/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Python-3.10+-blue?style=flat-square" alt="Python"></a><a href="https://github.com/Van-Zone/VanBot/blob/main/LICENSE" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/License-MIT-green?style=flat-square" alt="License"></a><a href="./.html"><img src="https://img.shields.io/badge/Supported%20Platforms-QQ%20%7C%20Kook-blueviolet?style=flat-square" alt="Supported Platforms"></a><a href="https://qm.qq.com/q/7jXfN4yGzB" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/QQ%20Group-1019070322-teal?style=flat-square" alt="QQ Group"></a></p><h2 id="✨-项目简介" tabindex="-1">✨ 项目简介 <a class="header-anchor" href="#✨-项目简介" aria-label="Permalink to &quot;✨ 项目简介&quot;">​</a></h2><p>本词库基于 Python 开发并适配 NoneBot 框架，专为 VanBot 提供稳定、灵活的关键词管理、对话匹配及语义解析能力。</p><p>无需额外适配开发，可直接集成至 VanBot 项目中，快速实现关键词触发、自动回复、指令匹配等核心场景；同时支持自定义词库导入与扩展，轻松满足 VanBot 个性化开发与场景化需求。</p><p><strong>本词库内置丰富变量</strong>，开发者可结合这些变量灵活拓展，实现多种多样的个性化功能，极大提升 VanBot 的交互能力与使用场景。</p><p>VanBot 已适配 <strong>QQ、Kook</strong> 等主流社交平台，本词库可同步适配所有 VanBot 支持的平台，确保多平台使用体验一致。</p><h2 id="📌-核心特性" tabindex="-1">📌 核心特性 <a class="header-anchor" href="#📌-核心特性" aria-label="Permalink to &quot;📌 核心特性&quot;">​</a></h2><ul><li>🧩 <strong>无缝集成</strong> — 完美对接 VanBot 架构，集成即生效，无需额外开发</li><li>🐍 <strong>版本兼容</strong> — 基于 Python 3.10+ 开发，兼容 NoneBot 主流版本</li><li>🔧 <strong>灵活扩展</strong> — 支持 <code>.txt</code> <code>.json</code> 格式词库导入，关键词增删改查灵活操作</li><li>📊 <strong>丰富变量支持</strong> — 内置大量变量，可结合变量拓展多样化功能，适配各类个性化需求</li><li>📄 <strong>开源免费</strong> — 基于 MIT 许可证，可自由用于个人及商业项目，支持二次开发</li><li>⚖️ <strong>规范引用</strong> — 使用本项目需标注来源，尊重开源成果与原作者权益</li><li>🌐 <strong>多平台支持</strong> — 同步适配 VanBot 已支持的 QQ、Kook 平台，适配无差异</li></ul><h2 id="🛠️-快速集成" tabindex="-1">🛠️ 快速集成 <a class="header-anchor" href="#🛠️-快速集成" aria-label="Permalink to &quot;🛠️ 快速集成&quot;">​</a></h2><ol><li>克隆 VanBot 项目至本地：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/ZiYiQuQ/VanBot.git</span></span></code></pre></div></li><li>进入项目目录，安装对应依赖（需 Python 3.10+）</li><li>在 VanBot 配置文件中启用本词库</li><li>启动 VanBot，词库自动加载生效（QQ、Kook 平台同步可用）</li></ol><blockquote><p>详细集成文档、词库使用示例、变量用法及配置教程，请参考 <a href="https://github.com/ZiYiQuQ/VanBot/wiki" target="_blank" rel="noreferrer">Wiki</a>（持续更新）</p></blockquote><h2 id="📖-词库结构" tabindex="-1">📖 词库结构 <a class="header-anchor" href="#📖-词库结构" aria-label="Permalink to &quot;📖 词库结构&quot;">​</a></h2><ul><li><strong>核心词库</strong> — 内置 VanBot 基础指令、常用对话关键词，适配 QQ、Kook 平台对话场景</li><li><strong>扩展词库</strong> — 预留独立自定义目录，支持外部词库导入，适配多样化使用需求</li><li><strong>变量模块</strong> — 内置丰富变量，支持变量调用与组合，助力功能拓展</li><li><strong>配置文件</strong> — 可灵活配置词库匹配规则、触发阈值等参数，按需调整功能效果</li></ul><h2 id="🔤-变量系统" tabindex="-1">🔤 变量系统 <a class="header-anchor" href="#🔤-变量系统" aria-label="Permalink to &quot;🔤 变量系统&quot;">​</a></h2><h3 id="基础变量" tabindex="-1">基础变量 <a class="header-anchor" href="#基础变量" aria-label="Permalink to &quot;基础变量&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td><code>[qq]</code></td><td>用户 QQ 号</td></tr><tr><td><code>[name]</code></td><td>用户昵称</td></tr><tr><td><code>[群号]</code></td><td>群组 ID</td></tr><tr><td><code>[词条id]</code></td><td>词条 ID</td></tr><tr><td><code>[词汇量]</code></td><td>词库词条数</td></tr><tr><td><code>[当前词库]</code></td><td>当前使用的词库名称</td></tr><tr><td><code>[n.1]</code> ~ <code>[n.5]</code></td><td>匹配变量占位符</td></tr></tbody></table><h3 id="匹配模式" tabindex="-1">匹配模式 <a class="header-anchor" href="#匹配模式" aria-label="Permalink to &quot;匹配模式&quot;">​</a></h3><ul><li><strong>精确匹配</strong> — 关键词必须完全匹配</li><li><strong>模糊匹配</strong> — 消息包含关键词即可触发</li><li><strong>管理员专用</strong> — 仅管理员可访问的特定词条</li></ul><h2 id="🤝-贡献指南" tabindex="-1">🤝 贡献指南 <a class="header-anchor" href="#🤝-贡献指南" aria-label="Permalink to &quot;🤝 贡献指南&quot;">​</a></h2><p>欢迎各位开发者参与本词库的开发与优化，共同完善 VanBot 生态！</p><ul><li>提交 Issue：反馈词库 Bug、提出功能建议或优化方向</li><li>提交 PR：贡献代码、补充词库内容、优化集成逻辑与使用体验</li><li>交流讨论：加入 VanBot QQ 官群，分享使用经验</li></ul><h2 id="📞-联系与反馈" tabindex="-1">📞 联系与反馈 <a class="header-anchor" href="#📞-联系与反馈" aria-label="Permalink to &quot;📞 联系与反馈&quot;">​</a></h2><ul><li><strong>项目地址</strong>：<a href="https://github.com/Van-Zone/VanBot" target="_blank" rel="noreferrer">https://github.com/Van-Zone/VanBot</a></li><li><strong>支持平台</strong>：QQ、Kook</li><li><strong>QQ 官群</strong>：<a href="https://qm.qq.com/q/7jXfN4yGzB" target="_blank" rel="noreferrer">1019070322</a></li><li><strong>许可证</strong>：<a href="https://github.com/Van-Zone/VanBot/blob/main/LICENSE" target="_blank" rel="noreferrer">MIT License</a></li></ul>',26)])])}const b=a(n,[["render",i]]);export{p as __pageData,b as default};
